using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder – happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 25m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(45m, order.Total);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.IsNotNull(order.Id);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsCorrectTotal()
    {
        var items = CreateItems(("Widget", 15.50m, 3));

        var order = _service.CreateOrder("cust-2", items);

        Assert.AreEqual(46.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_AddsOrderToInternalList()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(order.Id);
        Assert.AreSame(order, retrieved);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    #endregion

    #region CreateOrder – validation

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region CreateOrder – data-driven total calculation

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_CalculatesExpectedTotal(
        string description, List<OrderItem> items, decimal expectedTotal)
    {
        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total, $"Failed for: {description}");
    }

    public static IEnumerable<(string description, List<OrderItem> items, decimal expectedTotal)>
        TotalCalculationData =>
    [
        ("single item qty 1", CreateItems(("A", 20m, 1)), 20m),
        ("single item qty 5", CreateItems(("A", 10m, 5)), 50m),
        ("multiple items", CreateItems(("A", 10m, 2), ("B", 5m, 3)), 35m),
        ("zero price item", CreateItems(("Free", 0m, 10)), 0m),
    ];

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var result = _service.GetOrder(created.Id);

        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 10m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 20m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 30m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-nobody");

        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsCorrectCustomerIds()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 10m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 20m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        foreach (var order in result)
        {
            Assert.AreEqual("cust-1", order.CustomerId);
        }
    }

    #endregion
}

